# backend/shared/providers/e2b_html_renderer.py
#
# E2B-backed renderer for untrusted standalone HTML generated by Code
# image-to-HTML. The API and worker hosts must never execute generated HTML or
# JavaScript locally, so this helper writes only index.html into an isolated E2B
# sandbox, captures a Chromium screenshot there, and tears the sandbox down.
# The implementation is deliberately dependency-light so tests can inject a fake
# Sandbox class without making network calls.

from __future__ import annotations

import base64
import shlex
import time
from collections.abc import Callable
from dataclasses import dataclass
from typing import Any


RENDER_TIMEOUT_SECONDS = 0
BROWSER_PROCESS_TIMEOUT_SECONDS = 120
INSTALL_TIMEOUT_SECONDS = 600
DEFAULT_VIEWPORT_WIDTH = 1440
DEFAULT_VIEWPORT_HEIGHT = 1200
MIN_VIEWPORT_WIDTH = 320
MIN_VIEWPORT_HEIGHT = 240
MAX_VIEWPORT_WIDTH = 4096
MAX_VIEWPORT_HEIGHT = 4096
PLAYWRIGHT_INSTALL_COMMAND = """
if ! node -e "require.resolve('playwright')" >/dev/null 2>&1; then
  npm init -y >/dev/null 2>&1
  npm install --no-audit --no-fund playwright
fi
npx playwright install --with-deps chromium
""".strip()


def _screenshot_command(viewport_width: int, viewport_height: int) -> str:
    width = _bounded_int(viewport_width, MIN_VIEWPORT_WIDTH, MAX_VIEWPORT_WIDTH, DEFAULT_VIEWPORT_WIDTH)
    height = _bounded_int(viewport_height, MIN_VIEWPORT_HEIGHT, MAX_VIEWPORT_HEIGHT, DEFAULT_VIEWPORT_HEIGHT)
    return f"""
timeout {BROWSER_PROCESS_TIMEOUT_SECONDS}s node - <<'NODE'
const fs = require('fs');
const path = require('path');
const {{ chromium }} = require('playwright');

(async () => {{
  const browser = await chromium.launch({{
    headless: true,
    args: [
      '--no-sandbox',
      '--disable-gpu',
      '--disable-dev-shm-usage',
      '--disable-background-networking',
      '--host-resolver-rules=MAP * 0.0.0.0',
      '--no-zygote',
      '--single-process',
      '--js-flags=--jitless',
    ],
  }});
  try {{
    const page = await browser.newPage({{ viewport: {{ width: {width}, height: {height} }}, deviceScaleFactor: 1 }});
    await page.goto('file://' + path.join(process.cwd(), 'index.html'), {{ waitUntil: 'load', timeout: 60000 }});
    try {{ await page.evaluate(() => document.fonts && document.fonts.ready); }} catch (_) {{}}
    await page.waitForTimeout(250);
    await page.screenshot({{ path: '/tmp/openmates-render.png', fullPage: true }});
  }} finally {{
    await browser.close();
  }}
  const screenshot = fs.readFileSync('/tmp/openmates-render.png');
  if (!screenshot.length) {{
    throw new Error('empty screenshot file');
  }}
  process.stdout.write(screenshot.toString('base64'));
}})().catch((error) => {{
  console.error(error && error.stack ? error.stack : String(error));
  process.exit(1);
}});
NODE
""".strip()


def _bounded_int(value: int, minimum: int, maximum: int, default: int) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    return min(max(parsed, minimum), maximum)


@dataclass(frozen=True)
class E2BHtmlRenderResult:
    sandbox_id: str | None
    screenshot_bytes: bytes
    duration_seconds: float


def render_html_in_e2b(
    *,
    html: str,
    api_key: str,
    viewport_width: int = DEFAULT_VIEWPORT_WIDTH,
    viewport_height: int = DEFAULT_VIEWPORT_HEIGHT,
    sandbox_cls: Any | None = None,
    now: Callable[[], float] | None = None,
    monotonic: Callable[[], float] | None = None,
) -> E2BHtmlRenderResult:
    """Render untrusted HTML in E2B and return PNG screenshot bytes."""
    if not api_key.strip():
        raise RuntimeError("E2B API key is not configured")

    if sandbox_cls is None:
        try:
            from e2b import Sandbox
        except ImportError as exc:  # pragma: no cover - deployment dependency guard
            raise RuntimeError("E2B SDK is not installed in the API worker image") from exc
        sandbox_cls = Sandbox

    start_clock = now or time.monotonic
    end_clock = monotonic or time.monotonic
    started_at = start_clock()
    sandbox = _create_sandbox(sandbox_cls, api_key)
    sandbox_id = str(getattr(sandbox, "sandbox_id", "") or getattr(sandbox, "id", "") or "") or None

    try:
        sandbox.commands.run(f"bash -lc {shlex.quote(PLAYWRIGHT_INSTALL_COMMAND)}", timeout=INSTALL_TIMEOUT_SECONDS)
        sandbox.files.write_files([{"path": "index.html", "data": html}])
        command = f"bash -lc {shlex.quote(_screenshot_command(viewport_width, viewport_height))}"
        result = sandbox.commands.run(command, timeout=RENDER_TIMEOUT_SECONDS)
        exit_code = getattr(result, "exit_code", 0)
        screenshot_stdout = str(getattr(result, "stdout", "")).strip()
        if exit_code not in (0, None) or not screenshot_stdout:
            stderr = str(getattr(result, "stderr", "")).strip()
            raise RuntimeError(f"E2B HTML render failed with exit_code={exit_code}: {stderr or 'empty screenshot output'}")
        screenshot_bytes = base64.b64decode(screenshot_stdout)
        if not screenshot_bytes:
            raise RuntimeError("E2B HTML render returned an empty screenshot")
        return E2BHtmlRenderResult(
            sandbox_id=sandbox_id,
            screenshot_bytes=screenshot_bytes,
            duration_seconds=max(0.0, end_clock() - started_at),
        )
    finally:
        _cleanup_sandbox(sandbox_cls, sandbox, sandbox_id, api_key)


def _create_sandbox(sandbox_cls: Any, api_key: str) -> Any:
    kwargs = {
        "api_key": api_key,
        "secure": True,
        "allow_internet_access": True,
        "network": {"allow_public_traffic": False},
    }
    create = getattr(sandbox_cls, "create", None)
    if callable(create):
        return create(**kwargs)
    return sandbox_cls(**kwargs)


def _cleanup_sandbox(sandbox_cls: Any, sandbox: Any, sandbox_id: str | None, api_key: str) -> None:
    if sandbox_id:
        kill = getattr(sandbox_cls, "kill", None)
        if callable(kill):
            try:
                kill(sandbox_id=sandbox_id, api_key=api_key)
                return
            except Exception:
                pass

    for method_name in ("kill", "close"):
        method = getattr(sandbox, method_name, None)
        if callable(method):
            try:
                method()
            except Exception:
                pass
            return
